#include <bits/stdc++.h>
using namespace std;

struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {}
};

class Solution {
public:
    void deleteNode(ListNode* node) {
        if (!node || !node->next) return;
        ListNode* nxt = node->next;
        node->val = nxt->val;
        node->next = nxt->next;
        // optional: delete nxt; // not required for problem
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> vals(n);
    for (int i = 0; i < n; ++i) cin >> vals[i];
    int delVal;
    cin >> delVal;
    // Build linked list
    ListNode* head = new ListNode(vals[0]);
    ListNode* cur = head;
    ListNode* nodeToDelete = nullptr;
    if (head->val == delVal) nodeToDelete = head;
    for (int i = 1; i < n; ++i) {
        cur->next = new ListNode(vals[i]);
        cur = cur->next;
        if (vals[i] == delVal) nodeToDelete = cur;
    }
    Solution sol;
    sol.deleteNode(nodeToDelete);
    // Output list
    cur = head;
    bool first = true;
    while (cur) {
        if (!first) cout << ' ';
        first = false;
        cout << cur->val;
        cur = cur->next;
    }
    cout << '\n';
    return 0;
}
